function buildInitialState() {
  const claims = {...CLAIMS_2026}, scores = {};
  HOME_GAMES_2024.forEach(g => {
    if (g.who) claims[`2024-${g.id}`] = g.who;
  });
  HOME_GAMES_2025.forEach(g => {
    claims[`2025-${g.id}`] = g.who;
    scores[`2025-${g.id}`] = {status:'Final', result:g.R, cubsRuns:g.cR, oppRuns:g.oR};
  });
  return { claims, members: DEFAULT_MEMBERS, cachedScores: scores };
}

function loadState() {
  try {
    const r = localStorage.getItem(STORAGE_KEY);
    if (r) {
      const saved = JSON.parse(r);
      saved.claims = { ...CLAIMS_2026, ...saved.claims };
      return saved;
    }
  } catch {}
  return buildInitialState();
}

function isInPast(mlbDate) {
  const t = new Date(); t.setHours(0,0,0,0);
  return new Date(mlbDate+'T00:00:00') < t;
}

// ─── MLB API ────────────────────────────────────────────────────────────────
async function fetchGameDetails(mlbDate, gameType='R') {
  try {
    const url = `https://statsapi.mlb.com/api/v1/schedule?sportId=1&date=${mlbDate}&teamId=${CUBS_TEAM_ID}&gameType=${gameType}&hydrate=linescore,decisions,pitchers`;
    const res = await fetch(url);
    const data = await res.json();
    const dates = data.dates || [];
    if (!dates.length) return null;
    const game = dates[0].games.find(g => g.teams?.home?.team?.id === CUBS_TEAM_ID) 
                 || dates[0].games[0];
    if (!game) return null;
    const status = game.status?.abstractGameState;
    const isFinal = status === 'Final';
    const homeIsCubs = game.teams?.home?.team?.id === CUBS_TEAM_ID;
    const cubsTeam = homeIsCubs ? game.teams.home : game.teams.away;
    const oppTeam  = homeIsCubs ? game.teams.away : game.teams.home;
    const cubsRuns = cubsTeam?.score ?? 0;
    const oppRuns  = oppTeam?.score ?? 0;
    
    // Pitcher decisions — only include when data is complete and confident.
    // We require BOTH winner and loser to be present; if either is missing the
    // API data is incomplete and we surface nothing rather than risk wrong info.
    let decisions = null;
    if (isFinal && game.decisions) {
      const d = game.decisions;
      const winner = d.winner?.fullName || null;
      const loser  = d.loser?.fullName  || null;
      const save   = d.save?.fullName   || null;
      // Only show if the two mandatory fields are present
      if (winner && loser) {
        decisions = { winner, loser, save };
      }
    }

    return {
      status: isFinal ? 'Final' : (status || 'Preview'),
      cubsRuns, oppRuns,
      result: isFinal ? (cubsRuns > oppRuns ? 'W' : 'L') : null,
      decisions,
      gamePk: game.gamePk,
      oppName: oppTeam?.team?.name || '',
    };
  } catch { return null; }
}

