const calcRunDiff = (finalScores) => {
  const cR = finalScores.reduce((a,s) => a+(s.cubsRuns??0), 0);
  const oR = finalScores.reduce((a,s) => a+(s.oppRuns??0), 0);
  return cR - oR;
};

