// ─── RESULT BADGE ────────────────────────────────────────────────────────────
function ResultBadge({result, cubsRuns, oppRuns, size='sm'}) {
  const C = React.useContext(ThemeContext);
  const isW = result === 'W';
  // Win = W-flag: white bg, Cubs blue text, blue border
  // Loss = Cubs red bg, white text
  const bg       = isW ? '#FFFFFF' : C.red;
  const textClr  = isW ? C.blue    : '#FFFFFF';
  const scoreClr = isW ? C.blueMid : 'rgba(255,255,255,0.9)';
  const border   = isW ? `2px solid ${C.blue}` : '2px solid transparent';
  const fs = size === 'lg' ? 22 : 14;
  const scorefs = size === 'lg' ? 13 : 10;
  return (
    <div style={{display:'flex',flexDirection:'column',alignItems:'center',background:bg,border,borderRadius:4,padding:size==='lg'?'8px 12px':'5px 8px',minWidth:size==='lg'?50:36}}>
      <div style={{fontSize:fs,fontWeight:900,color:textClr,fontFamily:"'Bebas Neue',sans-serif",lineHeight:1}}>{result}</div>
      <div style={{fontSize:scorefs,color:scoreClr,fontFamily:"'Montserrat',sans-serif",marginTop:2}}>{cubsRuns}–{oppRuns}</div>
    </div>
  );
}

// ─── GAME CARD ────────────────────────────────────────────────────────────────
function GameCard({game, year, claimed, score, fetching, onClick}) {
  const C = React.useContext(ThemeContext);
  const past = isInPast(game.mlbDate);
  const isWin  = score?.result === 'W';
  const isLoss = score?.result === 'L';
  const isLive = score?.status === 'Live' || score?.status === 'In Progress';
  const isFinal = score?.status === 'Final';

  const borderColor = isWin ? C.blue : isLoss ? C.red : isLive ? '#E8A020' : C.border;
  const accentBg    = isWin ? C.blue : isLoss ? C.red : isLive ? '#b45309' : C.blue;

  return (
    <button
      onClick={onClick}
      style={{
        width:'100%', display:'flex', alignItems:'stretch',
        background: C.cream,
        borderLeft:`4px solid ${borderColor}`,
        border:`1px solid ${C.border}`,
        borderRadius:6, overflow:'hidden', cursor:'pointer', textAlign:'left',
        transition:'transform 0.12s,box-shadow 0.12s',
        boxShadow:'0 1px 3px rgba(0,0,0,0.06)',
      }}
    >
      {/* Date column */}
      <div style={{background:accentBg, minWidth:52, display:'flex',flexDirection:'column',alignItems:'center',justifyContent:'center',padding:'10px 6px',gap:1,flexShrink:0}}>
        <div style={{fontSize:13,color:'rgba(255,255,255,0.8)',textTransform:'uppercase',fontFamily:"'Bebas Neue',sans-serif",letterSpacing:'0.1em'}}>{game.dow}</div>
        <div style={{fontSize:26,fontWeight:700,color:'#fff',lineHeight:1,fontFamily:"'Bebas Neue',sans-serif"}}>{game.day}</div>
        <div style={{fontSize:13,color:'rgba(255,255,255,0.8)',textTransform:'uppercase',fontFamily:"'Bebas Neue',sans-serif",letterSpacing:'0.05em'}}>{MONTH_ABBR[game.month]}</div>
      </div>

      {/* Main info */}
      <div style={{flex:1,padding:'9px 11px',minWidth:0}}>
        <div style={{fontSize:17,fontWeight:700,color:C.ink,fontFamily:"'Bebas Neue',sans-serif",lineHeight:1.3,display:'flex',alignItems:'center',gap:5,overflow:'hidden'}}>
          <span style={{overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap',minWidth:0}}>vs. {game.opp}</span>
          {GIVEAWAYS[game.mlbDate] && <span style={{flexShrink:0,fontSize:13}}>🔔</span>}
        </div>
        <div style={{fontSize:15,color:C.muted,marginTop:3,fontFamily:"'Montserrat',sans-serif"}}>
          {game.time}
          {claimed
            ? <span style={{color:C.blue,fontWeight:700}}> · {claimed}</span>
            : <span style={{color:C.border}}> · Unassigned</span>}
        </div>
        {game.ticketType && (
          <div style={{marginTop:3,fontSize:14,fontFamily:"'Bebas Neue',sans-serif",letterSpacing:'0.06em',color:TICKET_COLOR[game.ticketType]||C.muted}}>
            {TICKET_EMOJI[game.ticketType]} {game.ticketType}
          </div>
        )}
        {isLive && <div style={{marginTop:3,fontSize:14,color:'#E8A020',fontFamily:"'Bebas Neue',sans-serif",letterSpacing:'0.05em'}}>🔴 LIVE · {score.cubsRuns??'-'}–{score.oppRuns??'-'}</div>}
      </div>

      {/* Right: score or status */}
      <div style={{display:'flex',alignItems:'center',justifyContent:'center',padding:'8px 10px',minWidth:52,flexShrink:0}}>
        {fetching && <Spinner size={12}/>}
        {!fetching && isFinal && <ResultBadge result={score.result} cubsRuns={score.cubsRuns} oppRuns={score.oppRuns}/>}
        {!fetching && !isFinal && !isLive && past && <div style={{width:28,height:28,borderRadius:'50%',border:`1.5px solid ${C.border}`,display:'flex',alignItems:'center',justifyContent:'center',color:C.muted,fontSize:15,fontWeight:700}}>?</div>}
        {!fetching && !isFinal && !isLive && !past && <div style={{fontSize:22,color:C.border}}>+</div>}
      </div>
    </button>
  );
}

// ─── GAME DETAIL MODAL ───────────────────────────────────────────────────────
function GameModal({game, year, score, claimed, members, wrigleyB64, onClose, onSave}) {
  const C = React.useContext(ThemeContext);
  const [selected, setSelected] = useState(claimed || '');
  const [details, setDetails] = useState(null);
  const [loadingDetails, setLoadingDetails] = useState(false);
  const past = isInPast(game.mlbDate);
  const isFinal = score?.status === 'Final';
  const giveaway = GIVEAWAYS[game.mlbDate] || null;

  useEffect(() => {
    if (isFinal && !details) {
      setLoadingDetails(true);
      fetchGameDetails(game.mlbDate).then(d => {
        setDetails(d);
        setLoadingDetails(false);
      });
    }
  }, [isFinal]);

  return (
    <div
      onClick={onClose}
      style={{position:'fixed',inset:0,background:'rgba(5,10,25,0.85)',display:'flex',alignItems:'flex-end',justifyContent:'center',zIndex:200,backdropFilter:'blur(4px)'}}
    >
      <div
        className="modal-slide"
        onClick={e=>e.stopPropagation()}
        style={{background:C.cream,width:'100%',maxWidth:480,maxHeight:'92vh',display:'flex',flexDirection:'column',borderRadius:'16px 16px 0 0',border:`2px solid ${C.border}`,borderBottom:'none',overflow:'hidden'}}
      >
        {/* Wrigley header photo */}
        {wrigleyB64 && (
          <div style={{height:120,overflow:'hidden',position:'relative',flexShrink:0}}>
            <img src={`data:image/jpeg;base64,${wrigleyB64}`} alt="Wrigley Field" style={{width:'100%',height:'100%',objectFit:'cover',objectPosition:'center 30%',filter:'brightness(0.65)'}}/>
            <div style={{position:'absolute',inset:0,background:'linear-gradient(to bottom, rgba(14,51,134,0.1), rgba(14,51,134,0.75))'}}/>
            {/* Overlay info */}
            <div style={{position:'absolute',bottom:0,left:0,right:0,padding:'12px 18px'}}>
              <div style={{fontSize:14,color:'rgba(255,255,255,0.7)',fontFamily:"'Bebas Neue',sans-serif",letterSpacing:'0.2em',textTransform:'uppercase',marginBottom:2}}>Wrigley Field · Chicago</div>
              <div style={{fontSize:20,fontWeight:700,color:'#fff',fontFamily:"'Bebas Neue',sans-serif",lineHeight:1.2,display:'flex',alignItems:'center',gap:8,flexWrap:'wrap'}}>
                <span>vs. {game.opp}</span>
                {game.ticketType && (
                  <span style={{fontSize:15,fontFamily:"'Bebas Neue',sans-serif",letterSpacing:'0.08em',padding:'2px 7px',borderRadius:3,background:'rgba(255,255,255,0.15)',color:'#fff'}}>
                    {TICKET_EMOJI[game.ticketType]} {game.ticketType}
                  </span>
                )}
              </div>
              <div style={{fontSize:15,color:'rgba(255,255,255,0.7)',fontFamily:"'Montserrat',sans-serif",marginTop:2}}>{game.dow}, {MONTH_ABBR[game.month]} {game.day} · {game.time}</div>
            </div>
            <button onClick={onClose} style={{position:'absolute',top:10,right:12,background:'rgba(0,0,0,0.3)',border:'none',color:'rgba(255,255,255,0.85)',fontSize:20,cursor:'pointer',padding:'4px 8px',borderRadius:4,lineHeight:1}}>✕</button>
          </div>
        )}
        {!wrigleyB64 && (
          <div style={{background:C.blue,padding:'16px 18px 12px',display:'flex',justifyContent:'space-between',alignItems:'flex-start',flexShrink:0}}>
            <div>
              <div style={{fontSize:14,color:'rgba(255,255,255,0.65)',fontFamily:"'Bebas Neue',sans-serif",letterSpacing:'0.2em',marginBottom:4}}>WRIGLEY FIELD · CHICAGO</div>
              <div style={{fontSize:20,fontWeight:700,color:'#fff',fontFamily:"'Bebas Neue',sans-serif"}}>vs. {game.opp}</div>
              <div style={{fontSize:15,color:'rgba(255,255,255,0.6)',marginTop:2}}>{game.dow}, {MONTH_ABBR[game.month]} {game.day} · {game.time}</div>
            </div>
            <button onClick={onClose} style={{background:'none',border:'none',color:'rgba(255,255,255,0.6)',fontSize:22,cursor:'pointer',padding:4}}>✕</button>
          </div>
        )}

        {/* Scrollable body */}
        <div style={{overflowY:'auto',flex:1,padding:'16px 18px'}}>

          {/* Score box for completed games */}
          {isFinal && score && (
            <div style={{background:C.cream,border:`1px solid ${C.border}`,borderRadius:8,overflow:'hidden',marginBottom:16,padding:0}}>
              <div style={{background:C.green,padding:'6px',textAlign:'center',marginBottom:12}}>
                <div style={{fontSize:13,color:C.cream,fontFamily:"'Bebas Neue',sans-serif",letterSpacing:'0.3em'}}>FINAL SCORE</div>
              </div>
              <div style={{display:'flex',alignItems:'center',justifyContent:'space-around',padding:'0 16px 12px'}}>
                <div style={{textAlign:'center'}}>
                  <div style={{fontSize:46,fontWeight:900,color:C.blue,fontFamily:"'Bebas Neue',sans-serif",lineHeight:1}}>{score.cubsRuns}</div>
                  <div style={{fontSize:13,color:C.muted,fontFamily:"'Bebas Neue',sans-serif",letterSpacing:'0.1em',marginTop:2}}>CUBS</div>
                </div>
                <div style={{display:'flex',flexDirection:'column',alignItems:'center',gap:4}}>
                  <div style={{background: score.result==='W'?'#FFFFFF':C.red,border:score.result==='W'?`2px solid ${C.blue}`:'2px solid transparent',borderRadius:6,padding:'8px 14px',minWidth:50,textAlign:'center'}}>
                    <div style={{fontSize:26,fontWeight:900,color:score.result==='W'?C.blue:'#fff',fontFamily:"'Bebas Neue',sans-serif",lineHeight:1}}>{score.result}</div>
                    <div style={{fontSize:13,color:score.result==='W'?C.muted:'rgba(255,255,255,0.8)',letterSpacing:'0.1em',marginTop:2}}>FINAL</div>
                  </div>
                </div>
                <div style={{textAlign:'center'}}>
                  <div style={{fontSize:46,fontWeight:900,color:C.ink,fontFamily:"'Bebas Neue',sans-serif",lineHeight:1}}>{score.oppRuns}</div>
                  <div style={{fontSize:13,color:C.muted,fontFamily:"'Bebas Neue',sans-serif",letterSpacing:'0.1em',marginTop:2,maxWidth:80,overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{game.opp.split(' ').slice(-1)[0].toUpperCase()}</div>
                </div>
              </div>

              {/* Pitcher decisions */}
              {loadingDetails && (
                <div style={{display:'flex',justifyContent:'center',marginTop:12}}><Spinner size={16}/></div>
              )}
              {details?.decisions && !loadingDetails && (
                <div style={{marginTop:14,borderTop:`1px solid ${C.border}`,paddingTop:12,paddingBottom:8,paddingLeft:4,paddingRight:4}}>
                  <div style={{fontSize:13,color:C.green,fontFamily:"'Bebas Neue',sans-serif",letterSpacing:'0.2em',textAlign:'center',marginBottom:8}}>PITCHING DECISIONS</div>
                  <div style={{display:'flex',flexDirection:'column',gap:5}}>
                    {details.decisions.winner && (
                      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',paddingTop:6,paddingBottom:6,borderBottom:`1px solid ${C.border}`}}>
                        <span style={{fontSize:14,color:C.green,fontFamily:"'Bebas Neue',sans-serif",letterSpacing:'0.1em'}}>WIN</span>
                        <span style={{fontSize:15,color:C.ink,fontFamily:"'Montserrat',sans-serif"}}>{details.decisions.winner}</span>
                      </div>
                    )}
                    {details.decisions.loser && (
                      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',paddingTop:6,paddingBottom:6,borderBottom:`1px solid ${C.border}`}}>
                        <span style={{fontSize:14,color:C.red,fontFamily:"'Bebas Neue',sans-serif",letterSpacing:'0.1em'}}>LOSS</span>
                        <span style={{fontSize:15,color:C.ink,fontFamily:"'Montserrat',sans-serif"}}>{details.decisions.loser}</span>
                      </div>
                    )}
                    {details.decisions.save && (
                      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',paddingTop:6,paddingBottom:6}}>
                        <span style={{fontSize:14,color:C.blue,fontFamily:"'Bebas Neue',sans-serif",letterSpacing:'0.1em'}}>SAVE</span>
                        <span style={{fontSize:15,color:C.ink,fontFamily:"'Montserrat',sans-serif"}}>{details.decisions.save}</span>
                      </div>
                    )}
                  </div>
                </div>
              )}
            </div>
          )}

          {score?.status === 'Live' && (
            <div style={{background:'rgba(228,160,32,0.15)',border:`1px solid #E8A020`,borderRadius:6,padding:'10px 14px',marginBottom:14,textAlign:'center'}}>
              <div style={{color:'#E8A020',fontSize:14,fontFamily:"'Bebas Neue',sans-serif",letterSpacing:'0.1em'}}>🔴 LIVE · CUBS {score.cubsRuns??'-'} – {score.oppRuns??'-'}</div>
            </div>
          )}

          {!past && !score && (
            <div style={{background:C.cream2,border:`1px solid ${C.border}`,borderRadius:6,padding:'10px 14px',marginBottom:14}}>
              <div style={{color:C.blue,fontSize:15,fontFamily:"'Montserrat',sans-serif",lineHeight:1.5}}>📅 Upcoming — assign now, score updates automatically after the game.</div>
            </div>
          )}

          {/* Assign section */}
          <div style={{fontSize:13,color:C.green,fontFamily:"'Bebas Neue',sans-serif",letterSpacing:'0.2em',marginBottom:10}}>ASSIGN TICKETS</div>
          <div style={{display:'flex',flexWrap:'wrap',gap:8,marginBottom:6}}>
            <button
              onClick={() => setSelected('')}
              style={{background:selected===''?C.red:'transparent',border:`1.5px solid ${selected===''?C.red:C.border}`,borderRadius:20,color:selected===''?'#fff':C.ink,padding:'7px 14px',fontSize:14,fontFamily:"'Montserrat',sans-serif",cursor:'pointer'}}
            >— None</button>
            {members.map(m => (
              <button key={m}
                onClick={() => setSelected(m)}
                style={{background:selected===m?C.blue:'transparent',border:`1.5px solid ${selected===m?C.blue:C.border}`,borderRadius:20,color:selected===m?C.cream:C.ink,padding:'7px 14px',fontSize:14,fontFamily:"'Montserrat',sans-serif",cursor:'pointer'}}
              >{m}</button>
            ))}
          </div>
        </div>


        {/* Giveaway section */}
        {giveaway && (
            <div style={{margin:'0 16px 14px',borderRadius:6,overflow:'hidden',border:`1px solid ${C.border}`}}>
              <div style={{background:C.green,padding:'10px 14px'}}>
                <div style={{fontSize:14,fontWeight:700,color:C.cream,fontFamily:"'Bebas Neue',sans-serif",letterSpacing:'0.25em'}}>🔔 DING! DING! DING!</div>
              </div>
              <div style={{background:C.cream2,padding:'12px 14px'}}>
                <div style={{fontSize:16,fontWeight:700,color:C.ink,fontFamily:"'Bebas Neue',sans-serif",marginBottom:4}}>{giveaway.item}</div>
                {giveaway.sponsor && <div style={{fontSize:12,color:C.blue,fontFamily:"'Bebas Neue',sans-serif",letterSpacing:'0.1em',marginBottom:8}}>{giveaway.sponsor}</div>}
                <div style={{fontSize:14,color:C.muted,fontFamily:"'Montserrat',sans-serif",lineHeight:1.6}}>{giveaway.desc}</div>
                <a href="https://www.mlb.com/cubs/tickets/promotions/gate-giveaways" target="_blank" rel="noopener noreferrer"
                  style={{display:'inline-block',marginTop:10,fontSize:15,color:C.blue,fontFamily:"'Bebas Neue',sans-serif",letterSpacing:'0.1em',textDecoration:'none',borderBottom:`1px solid ${C.blue}`}}>
                  VIEW ALL GATE GIVEAWAYS ↗
                </a>
              </div>
            </div>
        )}

        {/* Footer */}
        <div style={{display:'flex',gap:10,padding:'12px 16px',borderTop:`1px solid ${C.border}`,background:C.cream,flexShrink:0}}>
          <button onClick={onClose} style={{flex:1,background:'transparent',border:`1.5px solid ${C.border}`,borderRadius:5,color:C.muted,padding:'12px 0',fontSize:15,fontFamily:"'Montserrat',sans-serif",cursor:'pointer'}}>Cancel</button>
          <button
            onClick={() => { onSave(game.id, year, selected); onClose(); }}
            style={{flex:2,background:C.blue,border:'none',borderRadius:5,color:C.cream,padding:'12px 0',fontSize:15,fontWeight:700,fontFamily:"'Bebas Neue',sans-serif",letterSpacing:'0.1em',cursor:'pointer'}}
          >SAVE</button>
        </div>
      </div>
    </div>
  );
}

// ─── SCHEDULE TAB ────────────────────────────────────────────────────────────
function ScheduleTab({year, games, claims, scores, fetchingIds, members, onGameClick}) {
  const C = React.useContext(ThemeContext);
  const [monthFilter, setMonthFilter] = useState('all');
  const [memberFilter, setMemberFilter] = useState('all');
  const [ticketFilter, setTicketFilter] = useState('all');
  const [openMenu, setOpenMenu] = useState(null); // 'month'|'member'|'ticket'|null

  const TICKET_TIERS = ['BRONZE','SILVER','GOLD','PLATINUM','MARQUEE','DIAMOND'];
  const SCHEDULE_MONTHS = ['MARCH','APRIL','MAY','JUNE','JULY','AUGUST','SEPTEMBER','OCTOBER'];
  const availableMonths = SCHEDULE_MONTHS.filter(m => games.some(g => g.month === m));

  const filtered = games.filter(g => {
    const key = `${year}-${g.id}`;
    return (monthFilter === 'all' || g.month === monthFilter) &&
           (memberFilter === 'all' || claims[key] === memberFilter) &&
           (ticketFilter === 'all' || g.ticketType === ticketFilter);
  });

  const grouped = {};
  MONTH_ORDER.forEach(m => {
    const gms = filtered.filter(g => g.month === m);
    if (gms.length) grouped[m] = gms;
  });

  // Pill style — more subtle dropdown look
  const pillStyle = (active, isOpen) => ({
    background: active ? C.blue : isOpen ? C.cream3 : C.cream2,
    border: `1.5px solid ${active ? C.blue : isOpen ? C.blueMid : C.border}`,
    borderRadius: 8,
    color: active ? C.cream : C.ink,
    padding: '8px 16px',
    fontSize: 13,
    fontFamily: "'Bebas Neue',sans-serif",
    letterSpacing: '0.07em',
    cursor: 'pointer',
    whiteSpace: 'nowrap',
    display: 'flex',
    alignItems: 'center',
    gap: 5,
    transition: 'all 0.12s',
    userSelect: 'none',
  });

  const dropdownStyle = {
    position: 'absolute',
    top: '100%',
    left: 0,
    marginTop: 4,
    background: '#fff',
    border: `1.5px solid ${C.border}`,
    borderRadius: 8,
    boxShadow: '0 4px 16px rgba(0,0,0,0.13)',
    zIndex: 200,
    minWidth: 160,
    overflow: 'hidden',
  };

  const menuItemStyle = (selected) => ({
    padding: '9px 14px',
    fontSize: 14,
    fontFamily: "'Bebas Neue',sans-serif",
    letterSpacing: '0.06em',
    cursor: 'pointer',
    background: selected ? C.blue : 'transparent',
    color: selected ? '#fff' : C.ink,
    transition: 'background 0.1s',
    display: 'block',
    width: '100%',
    textAlign: 'left',
    border: 'none',
  });

  const chevron = (open) => (
    <span style={{fontSize:12, opacity:0.6, transform: open ? 'rotate(180deg)' : 'none', display:'inline-block', transition:'transform 0.15s'}}>▼</span>
  );

  const monthLabel = monthFilter === 'all' ? 'All Months' : monthFilter.charAt(0) + monthFilter.slice(1).toLowerCase();
  const memberLabel = memberFilter === 'all' ? 'Everyone' : memberFilter;
  const ticketLabel = ticketFilter === 'all' ? 'All Games' : ticketFilter.charAt(0) + ticketFilter.slice(1).toLowerCase();

  // Close menus when clicking outside
  const closeMenus = () => setOpenMenu(null);

  return (
    <div style={{paddingBottom:16}} onClick={closeMenus}>
      {/* 3-pill filter row */}
      <div style={{padding:'14px 14px 14px', display:'flex', gap:8, alignItems:'center', justifyContent:'center'}}>
        {/* Month pill */}
        <div style={{position:'relative'}} onClick={e => e.stopPropagation()}>
          <button style={pillStyle(monthFilter!=='all', openMenu==='month')}
            onClick={() => setOpenMenu(openMenu==='month' ? null : 'month')}>
            {monthLabel} {chevron(openMenu==='month')}
          </button>
          {openMenu === 'month' && (
            <div style={dropdownStyle}>
              {[{val:'all',label:'All Months'}, ...availableMonths.map(m => ({val:m, label:m.charAt(0)+m.slice(1).toLowerCase()}))].map(({val,label}) => (
                <button key={val} style={menuItemStyle(monthFilter===val)}
                  onClick={() => { setMonthFilter(val); setOpenMenu(null); }}>
                  {label}
                </button>
              ))}
            </div>
          )}
        </div>

        {/* Person pill */}
        <div style={{position:'relative'}} onClick={e => e.stopPropagation()}>
          <button style={pillStyle(memberFilter!=='all', openMenu==='member')}
            onClick={() => setOpenMenu(openMenu==='member' ? null : 'member')}>
            {memberLabel} {chevron(openMenu==='member')}
          </button>
          {openMenu === 'member' && (
            <div style={dropdownStyle}>
              {[{val:'all',label:'Everyone'}, ...members.map(m => ({val:m,label:m}))].map(({val,label}) => (
                <button key={val} style={menuItemStyle(memberFilter===val)}
                  onClick={() => { setMemberFilter(val); setOpenMenu(null); }}>
                  {label}
                </button>
              ))}
            </div>
          )}
        </div>

        {/* Ticket type pill */}
        <div style={{position:'relative'}} onClick={e => e.stopPropagation()}>
          <button style={pillStyle(ticketFilter!=='all', openMenu==='ticket')}
            onClick={() => setOpenMenu(openMenu==='ticket' ? null : 'ticket')}>
            {ticketLabel} {chevron(openMenu==='ticket')}
          </button>
          {openMenu === 'ticket' && (
            <div style={dropdownStyle}>
              {[{val:'all',label:'All Games'}, ...TICKET_TIERS.map(t => ({val:t, label:t.charAt(0)+t.slice(1).toLowerCase()}))].map(({val,label}) => (
                <button key={val} style={menuItemStyle(ticketFilter===val)}
                  onClick={() => { setTicketFilter(val); setOpenMenu(null); }}>
                  {val !== 'all' && <span style={{marginRight:5}}>{TICKET_EMOJI[val]}</span>}{label}
                </button>
              ))}
            </div>
          )}
        </div>
      </div>

      {/* Games by month */}
      <div style={{padding:'0 12px'}}>
        {Object.entries(grouped).map(([mo, gms]) => (
          <div key={mo}>
            <div style={{display:'flex',alignItems:'center',gap:8,margin:'14px 0 8px',paddingBottom:6,borderBottom:`2px solid ${C.green}`}}>
              <div style={{fontSize:14,color:C.green,fontFamily:"'Bebas Neue',sans-serif",letterSpacing:'0.3em',fontWeight:700}}>{mo}</div>
            </div>
            <div style={{display:'flex',flexDirection:'column',gap:7,marginBottom:4}}>
              {gms.map(g => {
                const key = `${year}-${g.id}`;
                return <GameCard key={g.id} game={g} year={year} claimed={claims[key]} score={scores[key]} fetching={fetchingIds.has(key)} onClick={() => onGameClick(g)}/>;
              })}
            </div>
          </div>
        ))}
        {filtered.length === 0 && (
          <div style={{textAlign:'center',padding:'40px 0',color:C.muted,fontFamily:"'Montserrat',sans-serif",fontSize:15,fontStyle:'italic'}}>No games match these filters</div>
        )}
      </div>
    </div>
  );
}

// ─── STATS TAB ───────────────────────────────────────────────────────────────
function StatsTab({claims, scores, members}) {
  const C = React.useContext(ThemeContext);
  const [statYear, setStatYear] = useState('all');

  const stats = React.useMemo(() => {
    return members.map(m => {
      let wins=0, losses=0, runDiff=0, totalCost=0;
      yearsFor(statYear).forEach(yr => {
        const gms = SEASONS[yr].filter(g => claims[`${yr}-${g.id}`] === m);
        totalCost += gms.reduce((a, g) => a + (g.price || 0), 0);
        const scs = gms.map(g => scores[`${yr}-${g.id}`]).filter(s => s?.status === 'Final');
        wins   += scs.filter(s => s.result === 'W').length;
        losses += scs.filter(s => s.result === 'L').length;
        runDiff += calcRunDiff(scs);
      });
            const costPerWin = (wins > 0 && totalCost > 0) ? totalCost / wins : null;
      return {name:m, played:wins+losses, wins, losses, runDiff, totalCost, costPerWin};
    }).sort((a,b) => {
      const aP = a.played>0 ? a.wins/a.played : -1;
      const bP = b.played>0 ? b.wins/b.played : -1;
      return bP - aP || b.wins - a.wins;
    });
  }, [members, claims, scores, statYear]);

  const MEDAL = ['🥇','🥈','🥉'];
  const rankColors = [C.blue, '#9AA5B1', '#B87C3A'];

  return (
    <div style={{padding:'14px 12px 16px'}}>
      {/* Year filter */}
      <div style={{display:'flex',gap:6,marginBottom:16}}>
        {['all',...SEASON_YEARS].map(yr => (
          <button key={yr} onClick={()=>setStatYear(yr)} style={yearBtnStyle(statYear===yr, C)}>
            {yr==='all'?'ALL TIME':yr}
          </button>
        ))}
      </div>

      {stats.map((s,i) => {
        const winPct = s.played > 0 ? Math.round((s.wins/s.played)*1000)/10 : null;
        const rd = s.runDiff;
        const isTop = i < 3;
        return (
          <div key={s.name} style={{display:'flex',gap:11,background:C.cream,border:`1px solid ${C.border}`,borderLeft:`4px solid ${isTop && s.played>0 ? rankColors[i] : C.border}`,borderRadius:7,padding:'12px 13px',marginBottom:10}}>
            <div style={{display:'flex',flexDirection:'column',alignItems:'center',justifyContent:'flex-start',minWidth:32,paddingTop:2}}>
              {s.played > 0
                ? <div style={{fontSize:18}}>{i<3?MEDAL[i]:`#${i+1}`}</div>
                : <div style={{fontSize:15,color:C.muted,fontFamily:"'Bebas Neue',sans-serif"}}>#{i+1}</div>}
            </div>
            <div style={{flex:1,minWidth:0}}>
              <div style={{fontSize:18,fontWeight:700,color:C.ink,fontFamily:"'Bebas Neue',sans-serif",marginBottom:8}}>{s.name}</div>
              <div style={{display:'flex',gap:7,flexWrap:'wrap'}}>
                {[
                  [s.played>0?`${s.wins}–${s.losses}`:'—', 'W–L',      s.wins>s.losses?C.green:s.wins<s.losses?C.red:C.ink],
                  [winPct!==null?`${winPct}%`:'—',         'Win%',     winPct>=50?C.green:winPct!==null?C.red:C.ink],
                  [s.played>0?(rd>0?`+${rd}`:String(rd)):'—','Run Diff', rd>0?C.green:rd<0?C.red:C.ink],
                  [s.costPerWin!=null?`$${s.costPerWin.toFixed(0)}`:'—', '$/Win', C.blue],
                ].map(([val,lbl,clr]) => (
                  <div key={lbl} style={{flex:'1 1 22%',background:C.cream2,border:`1px solid ${C.border}`,borderRadius:3,padding:'7px 6px',textAlign:'center',minWidth:55}}>
                    <div style={{fontSize:18,fontWeight:700,color:clr,fontFamily:"'Bebas Neue',sans-serif",lineHeight:1}}>{val}</div>
                    <div style={{fontSize:13,color:C.muted,fontFamily:"'Bebas Neue',sans-serif",letterSpacing:'0.1em',marginTop:3}}>{lbl}</div>
                  </div>
                ))}
              </div>
              {s.played===0 && <div style={{fontSize:15,color:C.muted,fontFamily:"'Montserrat',sans-serif",marginTop:6,fontStyle:'italic'}}>No games played yet</div>}
            </div>
          </div>
        );
      })}
    </div>
  );
}

// ─── LEADERBOARD TAB ─────────────────────────────────────────────────────────
function LeaderboardTab({claims, scores, members}) {
  const C = React.useContext(ThemeContext);
  const [boardYear, setBoardYear] = useState('all');

  const ranked = React.useMemo(() => members.map(m => {
    let wins=0,losses=0,runDiff=0;
    yearsFor(boardYear).forEach(yr => {
      const gms = SEASONS[yr].filter(g => claims[`${yr}-${g.id}`] === m);
      const scs = gms.map(g => scores[`${yr}-${g.id}`]).filter(s => s?.status==='Final');
      wins   += scs.filter(s=>s.result==='W').length;
      losses += scs.filter(s=>s.result==='L').length;
      runDiff += calcRunDiff(scs);
    });
    const played = wins+losses;
    const winPct = played>0 ? wins/played : 0;
    return {name:m, wins, losses, played, runDiff, winPct};
  }).sort((a,b)=>b.winPct-a.winPct||b.wins-a.wins), [members, claims, scores, boardYear]);

  const MEDAL = ['🥇','🥈','🥉'];

  return (
    <div style={{padding:'14px 12px 16px'}}>
      {/* Year filter */}
      <div style={{display:'flex',gap:6,marginBottom:16}}>
        {['all',...SEASON_YEARS].map(yr => (
          <button key={yr} onClick={()=>setBoardYear(yr)} style={yearBtnStyle(boardYear===yr, C)}>
            {yr==='all'?'ALL TIME':yr}
          </button>
        ))}
      </div>

      {ranked.filter(m=>m.played>0).map((m,i) => {
        const pct = Math.round(m.winPct*1000)/10;
        return (
          <div key={m.name} style={{display:'flex',alignItems:'center',gap:10,background:C.cream,border:`1px solid ${C.border}`,borderLeft:`4px solid ${i===0?C.blue:i===1?'#9AA5B1':i===2?'#B87C3A':C.border}`,borderRadius:6,padding:'11px 13px',marginBottom:8}}>
            <div style={{fontSize:22,width:28,textAlign:'center',flexShrink:0}}>{i<3?MEDAL[i]:`#${i+1}`}</div>
            <div style={{flex:1}}>
              <div style={{fontSize:18,fontWeight:700,color:C.ink,fontFamily:"'Bebas Neue',sans-serif",marginBottom:3}}>{m.name}</div>
              <div style={{display:'flex',alignItems:'center',gap:6,flexWrap:'wrap'}}>
                <span style={{fontSize:18,fontWeight:700,color:m.wins>m.losses?C.green:m.wins<m.losses?C.red:C.ink,fontFamily:"'Bebas Neue',sans-serif"}}>{m.wins}–{m.losses}</span>
                <span style={{color:C.border,fontSize:12}}>·</span>
                <span style={{fontSize:15,color:C.muted,fontFamily:"'Bebas Neue',sans-serif"}}>{pct}%</span>
                <span style={{color:C.border,fontSize:12}}>·</span>
                <span style={{fontSize:15,fontFamily:"'Bebas Neue',sans-serif",color:m.runDiff>0?C.green:m.runDiff<0?C.red:C.muted,fontWeight:600}}>{m.runDiff>0?'+':''}{m.runDiff} RD</span>
              </div>
            </div>
            <div style={{fontSize:14,color:C.muted,fontFamily:"'Bebas Neue',sans-serif",flexShrink:0}}>{m.played} Games</div>
          </div>
        );
      })}
      {ranked.every(m=>m.played===0) && (
        <div style={{textAlign:'center',padding:'32px 0',color:C.muted,fontFamily:"'Montserrat',sans-serif",fontSize:15,fontStyle:'italic'}}>No results yet</div>
      )}
    </div>
  );
}

