// ─── STANDINGS TAB ───────────────────────────────────────────────────────────
const NL_CENTRAL_IDS = {
  112: {name:'Chicago',     abbr:'CHC'},
  158: {name:'Milwaukee',   abbr:'MIL'},
  138: {name:'St. Louis',   abbr:'STL'},
  113: {name:'Cincinnati',  abbr:'CIN'},
  134: {name:'Pittsburgh',  abbr:'PIT'},
};

const COL_HDR = {
  background:C.green, color:C.cream,
  fontFamily:"'Bebas Neue',sans-serif", fontSize:12,
  letterSpacing:'0.12em', padding:'8px 6px', textAlign:'center'
};

function StandingsTab() {
  const C = React.useContext(ThemeContext);
  const [rows, setRows]       = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError]     = useState(null);
  const [updated, setUpdated] = useState(null);

  const parseTeamRecord = (r) => ({
    teamId:  r.team.id,
    name:    NL_CENTRAL_IDS[r.team.id]?.name  || r.team.teamName || r.team.name,
    abbr:    NL_CENTRAL_IDS[r.team.id]?.abbr  || r.team.abbreviation,

    w:       r.wins ?? 0,
    l:       r.losses ?? 0,
    pct:     r.winningPercentage ?? '.000',
    gb:      r.divisionGamesBack ?? '-',
    streak:  r.streak?.streakCode || '—',
    last10:  (() => { const s = r.records?.splitRecords?.find(x=>x.type==='lastTen'); return s ? `${s.wins}-${s.losses}` : '—'; })(),
    isCubs:  r.team.id === 112,
  });

  const PRESEASON_ROWS = Object.entries(NL_CENTRAL_IDS).map(([id, info]) => ({
    teamId: Number(id), name: info.name, abbr: info.abbr, w:0, l:0, pct:'.000', gb:'-', streak:'—', last10:'—', isCubs: Number(id)===112,
  }));

  const fetchStandings = useCallback(async () => {
    setLoading(true); setError(null);
    try {
      const season = new Date().getFullYear();
      // Try multiple standing types in order of preference
      const types = ['regularSeason', 'springTraining', 'preseason'];
      let found = null;
      for (const sType of types) {
        const res = await fetch(
          `https://statsapi.mlb.com/api/v1/standings?leagueId=104&season=${season}&standingsTypes=${sType}&hydrate=team,division`
        );
        const data = await res.json();
        const div = data.records?.find(r => r.division?.id === 205);
        if (div && div.teamRecords?.length > 0) { found = div; break; }
      }
      if (found) {
        const sorted = [...found.teamRecords].sort((a,b) => {
          // Sort by wins desc if season started, else by team name
          if (a.wins === 0 && b.wins === 0 && a.losses === 0 && b.losses === 0) {
            return (NL_CENTRAL_IDS[a.team.id]?.name||'').localeCompare(NL_CENTRAL_IDS[b.team.id]?.name||'');
          }
          return (a.divisionRank||99) - (b.divisionRank||99);
        });
        setRows(sorted.map(parseTeamRecord));
      } else {
        // Preseason — show all teams at 0-0 alphabetically
        setRows(PRESEASON_ROWS.sort((a,b)=>a.name.localeCompare(b.name)));
      }
      setUpdated(new Date().toLocaleTimeString([], {hour:'2-digit',minute:'2-digit'}));
    } catch(e) {
      // Network error — still show teams at 0-0 rather than error message
      setRows(PRESEASON_ROWS.sort((a,b)=>a.name.localeCompare(b.name)));
      setUpdated('Offline');
    }
    setLoading(false);
  }, []);

  useEffect(() => { fetchStandings(); }, [fetchStandings]);

  return (
    <div style={{padding:'14px 12px 16px'}}>
      {/* Scoreboard header */}
      <div style={{background:C.green,borderRadius:'6px 6px 0 0',padding:'10px 14px',display:'flex',justifyContent:'space-between',alignItems:'center'}}>
        <div style={{fontSize:15,fontWeight:700,color:C.cream,fontFamily:"'Bebas Neue',sans-serif",letterSpacing:'0.2em'}}>NL CENTRAL</div>
        <button onClick={fetchStandings} style={{background:'none',border:'none',color:'rgba(248,246,242,0.7)',fontSize:16,cursor:'pointer',padding:'2px 6px'}}>↻</button>
      </div>

      {/* Column headers */}
      <div style={{display:'grid',gridTemplateColumns:'1fr 36px 36px 44px 44px 44px 44px',background:C.green,borderTop:'1px solid rgba(255,255,255,0.15)'}}>
        <div style={{...COL_HDR,textAlign:'left',paddingLeft:10}}>TEAM</div>
        <div style={COL_HDR}>W</div>
        <div style={COL_HDR}>L</div>
        <div style={COL_HDR}>PCT</div>
        <div style={COL_HDR}>GB</div>
        <div style={COL_HDR}>L10</div>
        <div style={COL_HDR}>STK</div>
      </div>

      {/* Rows */}
      <div style={{background:C.green,borderTop:'1px solid rgba(255,255,255,0.12)',borderRadius:'0 0 6px 6px',overflow:'hidden'}}>
        {loading && (
          <div style={{padding:'32px',textAlign:'center',background:C.green}}><Spinner size={20} color='rgba(255,255,255,0.7)'/></div>
        )}

        {!loading && rows.map((row, i) => {
          const isCubs = row.isCubs;
          const rowBg = isCubs ? 'rgba(255,255,255,0.18)' : (i%2===0 ? 'rgba(255,255,255,0.07)' : 'transparent');
          return (
            <div key={row.teamId} style={{
              display:'grid', gridTemplateColumns:'1fr 36px 36px 44px 44px 44px 44px',
              background: rowBg,
              borderBottom: i < rows.length-1 ? '1px solid rgba(255,255,255,0.12)' : 'none',
            }}>
              {/* Team */}
              <div style={{display:'flex',alignItems:'center',padding:'10px 12px'}}>
                <div style={{fontSize:17,fontWeight:700,color: isCubs ? '#fff' : 'rgba(255,255,255,0.85)',fontFamily:"'Bebas Neue',sans-serif",letterSpacing:'0.05em'}}>{row.name}</div>
              </div>
              {/* Stats */}
              {[row.w, row.l, row.pct, row.gb==='0.0'?'-':row.gb, row.last10, row.streak].map((val,ci) => (
                <div key={ci} style={{
                  display:'flex',alignItems:'center',justifyContent:'center',
                  fontSize: ci<2 ? 14 : 11,
                  fontWeight: ci<2 ? 700 : 400,
                  color: isCubs ? '#fff' : (ci<2 ? 'rgba(255,255,255,0.9)' : 'rgba(255,255,255,0.6)'),
                  fontFamily: ci<2 ? "'Bebas Neue',sans-serif" : "'Montserrat',sans-serif",
                  padding:'4px 2px',
                }}>
                  {val}
                </div>
              ))}
            </div>
          );
        })}
      </div>

      {updated && (
        <div style={{fontSize:12,color:C.green,fontFamily:"'Bebas Neue',sans-serif",letterSpacing:'0.08em',marginTop:10,textAlign:'center'}}>
          UPDATED · {updated}
        </div>
      )}
    </div>
  );
}
// ─── SETTINGS TAB ─────────────────────────────────────────────────────────────
function RosterTab({members, setMembers, renameMember, onRefresh, lastUpdated, onToggleDark, fbReady}) {
  const C = React.useContext(ThemeContext);
  const isDark = C === C_DARK;
  const [newName, setNewName]   = useState('');
  const [editingIdx, setEditingIdx] = useState(null);
  const [editValue, setEditValue]   = useState('');

  const add = () => {
    const n = newName.trim();
    if (n && !members.includes(n)) { setMembers([...members,n]); setNewName(''); }
  };
  const startEdit = (i) => { setEditingIdx(i); setEditValue(members[i]); };
  const commitEdit = () => {
    const n = editValue.trim();
    if (n && editingIdx !== null) {
      const oldName = members[editingIdx];
      if (n !== oldName) renameMember(oldName, n);
    }
    setEditingIdx(null);
  };
  const cancelEdit = () => setEditingIdx(null);

  const avatarLetter = name => name.replace(/\s*\/.*$/,'').trim()[0].toUpperCase();

  const inputStyle = {
    flex:1, background:'rgba(255,255,255,0.15)',
    border:'1.5px solid rgba(255,255,255,0.35)',
    borderRadius:5, color:'#fff', fontSize:15,
    padding:'8px 11px', outline:'none',
    fontFamily:"'Montserrat',sans-serif",
  };

  const Section = ({title, children}) => (
    <div style={{marginBottom:16,borderRadius:6,overflow:'hidden',border:'none'}}>
      <div style={{background:C.green,padding:'10px 14px',borderRadius:'6px 6px 0 0'}}>
        <div style={{fontSize:15,color:C.cream,fontFamily:"'Bebas Neue',sans-serif",letterSpacing:'0.25em'}}>{title}</div>
      </div>
      <div style={{background:C.green,padding:'14px',borderRadius:'0 0 6px 6px',borderTop:'1px solid rgba(255,255,255,0.15)'}}>
        {children}
      </div>
    </div>
  );

  return (
    <div style={{padding:'14px 12px 16px'}}>

      <Section title="GROUP MEMBERS">
        {members.map((m,i) => (
          <div key={i} style={{
            display:'flex', alignItems:'center', gap:8,
            padding:'9px 0',
            borderBottom: i < members.length-1 ? '1px solid rgba(255,255,255,0.2)' : 'none'
          }}>
            <div style={{width:32,height:32,borderRadius:4,background:'rgba(255,255,255,0.15)',color:C.cream,display:'flex',alignItems:'center',justifyContent:'center',fontWeight:900,fontSize:17,fontFamily:"'Bebas Neue',sans-serif",flexShrink:0,border:'1px solid rgba(255,255,255,0.25)'}}>{avatarLetter(m)}</div>
            {editingIdx === i ? (
              <>
                <input
                  autoFocus
                  value={editValue} onChange={e=>setEditValue(e.target.value)}
                  onKeyDown={e=>{ if(e.key==='Enter') commitEdit(); if(e.key==='Escape') cancelEdit(); }}
                  style={{...inputStyle, flex:1}}
                />
                <button onClick={commitEdit} style={{background:'rgba(255,255,255,0.25)',border:'1px solid rgba(255,255,255,0.5)',color:'#fff',fontSize:15,cursor:'pointer',padding:'5px 10px',borderRadius:3,fontFamily:"'Bebas Neue',sans-serif",letterSpacing:'0.05em'}}>SAVE</button>
                <button onClick={cancelEdit} style={{background:'none',border:'1px solid rgba(255,255,255,0.2)',color:'rgba(255,255,255,0.5)',fontSize:14,cursor:'pointer',padding:'5px 8px',borderRadius:3}}>✕</button>
              </>
            ) : (
              <>
                <span style={{flex:1,fontSize:16,color:'#fff',fontFamily:"'Montserrat',sans-serif",fontWeight:500}}>{m}</span>
                <button onClick={()=>startEdit(i)} style={{background:'none',border:'1px solid rgba(255,255,255,0.25)',color:'rgba(255,255,255,0.6)',fontSize:13,cursor:'pointer',padding:'4px 9px',borderRadius:3,fontFamily:"'Bebas Neue',sans-serif",letterSpacing:'0.05em'}}>EDIT</button>
                <button onClick={()=>setMembers(members.filter((_,j)=>j!==i))} style={{background:'none',border:'1px solid rgba(255,255,255,0.25)',color:'rgba(255,255,255,0.4)',fontSize:15,cursor:'pointer',padding:'4px 8px',borderRadius:3,lineHeight:1}}>✕</button>
              </>
            )}
          </div>
        ))}

        {/* Add new */}
        <div style={{display:'flex',gap:8,marginTop:14}}>
          <input
            value={newName} onChange={e=>setNewName(e.target.value)}
            onKeyDown={e=>e.key==='Enter'&&add()}
            placeholder="Add member..."
            className="green-input"
            style={{...inputStyle, flex:1}}
          />
          <button onClick={add} style={{background:'rgba(255,255,255,0.2)',border:'1.5px solid rgba(255,255,255,0.5)',borderRadius:5,color:'#fff',fontWeight:700,fontSize:15,padding:'9px 16px',fontFamily:"'Bebas Neue',sans-serif",letterSpacing:'0.05em',cursor:'pointer'}}>ADD</button>
        </div>
      </Section>

      <Section title="LIVE SCORE SYNC">
        <div style={{display:'flex',alignItems:'center',gap:8,marginBottom:14}}>
          <div style={{width:9,height:9,borderRadius:'50%',background:fbReady?'#4ade80':'rgba(255,255,255,0.35)',boxShadow:fbReady?'0 0 6px #4ade80':'none',flexShrink:0,transition:'background 0.5s'}}/>
          <div style={{fontSize:13,color:'rgba(255,255,255,0.75)',fontFamily:"'Montserrat',sans-serif"}}>{fbReady ? 'Live — syncing with all shareholders' : 'Connecting to shared database…'}</div>
        </div>
        <div style={{fontSize:15,color:'rgba(255,255,255,0.85)',fontFamily:"'Montserrat',sans-serif",lineHeight:1.7,marginBottom:14}}>
          2025 results are locked. 2026 scores update automatically from the MLB Stats API.
        </div>
        {lastUpdated && (
          <div style={{fontSize:12,color:'rgba(255,255,255,0.7)',fontFamily:"'Bebas Neue',sans-serif",marginBottom:12,letterSpacing:'0.08em',padding:'6px 10px',background:'rgba(255,255,255,0.1)',borderRadius:4,display:'inline-block',border:'1px solid rgba(255,255,255,0.2)'}}>
            LAST SYNCED · {lastUpdated}
          </div>
        )}
        <button onClick={onRefresh} style={{background:'rgba(255,255,255,0.15)',border:'1.5px solid rgba(255,255,255,0.5)',borderRadius:5,color:'#fff',fontWeight:700,fontSize:15,padding:'11px 20px',fontFamily:"'Bebas Neue',sans-serif",letterSpacing:'0.1em',cursor:'pointer',width:'100%',marginTop:4}}>↻  REFRESH SCORES</button>
      </Section>

      <Section title="APPEARANCE">
        <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',padding:'4px 0'}}>
          <div>
            <div style={{fontSize:15,color:'#fff',fontFamily:"'Montserrat',sans-serif",fontWeight:500}}>{isDark ? '🌙 Dark Mode' : '☀️ Light Mode'}</div>
            <div style={{fontSize:12,color:'rgba(255,255,255,0.55)',fontFamily:"'Montserrat',sans-serif",marginTop:3}}>{isDark ? 'Dark theme enabled' : 'Light theme active'}</div>
          </div>
          <button onClick={onToggleDark} aria-label="Toggle dark mode" style={{
            width:52,height:30,borderRadius:15,
            background: isDark ? '#1A4AAA' : 'rgba(255,255,255,0.25)',
            border:'1.5px solid rgba(255,255,255,0.4)',
            cursor:'pointer',padding:0,position:'relative',
            transition:'background 0.3s',flexShrink:0,
          }}>
            <div style={{
              position:'absolute',top:4,
              left: isDark ? 24 : 4,
              width:20,height:20,borderRadius:'50%',
              background:'#fff',transition:'left 0.25s',
              boxShadow:'0 1px 5px rgba(0,0,0,0.4)',
              display:'flex',alignItems:'center',justifyContent:'center',
              fontSize:11,
            }}>{isDark ? '🌙' : '☀️'}</div>
          </button>
        </div>
      </Section>

      <Section title="ABOUT">
        <div style={{fontSize:15,color:'rgba(255,255,255,0.85)',fontFamily:"'Montserrat',sans-serif",lineHeight:2}}>
          Chicago Cubs · Wrigley Field<br/>
          Section 213 · Row 2 · Seats 3 &amp; 4<br/>
          Est. 1876 · Chicago National League Ball Club
        </div>
      </Section>

    </div>
  );
}

