const CAMPANA_BATTING_B64 = "";
const CAMPANA_CARD_B64    = "";
const HOF_LOGO_B64        = "";

function CampanaPage({onBack, logoB64}) {
  return (
    <div style={{
      background:'#000080', minHeight:'100vh', maxWidth:480, margin:'0 auto',
      fontFamily:'Times New Roman, serif', color:'#ffff00',
      border:'4px solid #ff0000', position:'relative',
    }}>

      {/* Same header — logo click goes back */}
      <div style={{background:'#000080', borderBottom:'3px solid #ff0000', padding:'10px 14px 8px', display:'flex', alignItems:'center', gap:10}}>
        {logoB64 && (
          <img src={`data:image/png;base64,${logoB64}`} alt="Cubs" onClick={onBack}
            style={{width:36,height:36,borderRadius:'50%',cursor:'pointer',border:'2px solid #ffff00',boxShadow:'0 0 12px #ffff00'}}/>
        )}
        <div style={{color:'#ffff00',fontFamily:'Times New Roman',fontWeight:700,fontSize:18}}>← CLICK LOGO TO EXIT THIS SITE</div>
      </div>

      {/* Marquee hack zone */}
      <div style={{textAlign:'center', padding:'10px 0', background:'#ff0000'}}>
        <marquee style={{color:'#ffff00',fontWeight:900,fontSize:18,fontFamily:'Comic Sans MS, cursive'}}>
          ★ WELCOME ★ YOU HAVE BEEN HACKED ★ TONY CAMPANA FOR THE HOF ★ SPREAD THE WORD ★ WELCOME ★ YOU HAVE BEEN HACKED ★
        </marquee>
      </div>

      {/* Title */}
      <div style={{textAlign:'center', padding:'18px 12px 8px'}}>
        <div style={{fontSize:13, color:'#00ffff', letterSpacing:'0.2em', textTransform:'uppercase', marginBottom:6}}>✦ OFFICIAL FAN SITE ✦ EST. 2011 ✦ VISITOR COUNT: 1,337 ✦</div>
        <div style={{fontSize:28, fontWeight:900, color:'#ffff00', textShadow:'3px 3px 0 #ff0000, -1px -1px 0 #ff0000', lineHeight:1.1, fontFamily:'Impact, Arial Black, sans-serif'}}>
          WELCOME TO THE<br/>
          <span style={{color:'#00ff00'}}>TONY CAMPANA</span><br/>
          FOR THE BASEBALL<br/>HALL OF FAME CLUB
        </div>
        <div style={{fontSize:14, color:'#ff9900', marginTop:8, fontStyle:'italic'}}>~ The Greatest Cub of All Time (We Think) ~</div>
      </div>

      {/* HOF Logo */}
      <div style={{textAlign:'center', padding:'10px 0'}}>
        <img src={`data:image/png;base64,${HOF_LOGO_B64}`} alt="Hall of Fame"
          style={{width:100, border:'4px solid #ffff00', boxShadow:'0 0 20px #ff0000'}}/>
        <div style={{fontSize:11, color:'#00ffff', marginTop:4, letterSpacing:'0.1em'}}>⚾ HE BELONGS HERE ⚾</div>
      </div>

      <hr style={{border:'2px dashed #ff0000', margin:'0 16px'}}/>

      {/* Batting photo */}
      <div style={{textAlign:'center', padding:'16px 12px 8px'}}>
        <div style={{fontSize:14, color:'#ff9900', marginBottom:8, fontWeight:700, textTransform:'uppercase', letterSpacing:'0.15em'}}>🏆 Tony in Action at Wrigley 🏆</div>
        <img src={`data:image/jpeg;base64,${CAMPANA_BATTING_B64}`} alt="Tony Campana batting"
          style={{width:'100%', maxWidth:340, border:'5px solid #ffff00', boxShadow:'0 0 25px #00ff00'}}/>
        <div style={{fontSize:12, color:'#00ffff', marginTop:6, fontStyle:'italic'}}>
          "The fastest man in the history of the Chicago Cubs probably"
        </div>
      </div>

      <hr style={{border:'2px dashed #ff0000', margin:'0 16px'}}/>

      {/* Baseball card */}
      <div style={{textAlign:'center', padding:'16px 12px 8px'}}>
        <div style={{fontSize:14, color:'#ff9900', marginBottom:8, fontWeight:700, textTransform:'uppercase', letterSpacing:'0.15em'}}>🎴 His Legendary Rookie Card 🎴</div>
        <img src={`data:image/jpeg;base64,${CAMPANA_CARD_B64}`} alt="Tony Campana Topps card"
          style={{width:'100%', maxWidth:380, border:'5px solid #00ff00', boxShadow:'0 0 25px #ffff00'}}/>
        <div style={{fontSize:11, color:'#00ffff', marginTop:6, fontStyle:'italic'}}>
          Topps Update Series 2011 · Card #US57 · Worth at least $3.50
        </div>
      </div>

      <hr style={{border:'2px dashed #ff0000', margin:'0 16px'}}/>

      {/* Stats and manifesto */}
      <div style={{padding:'14px 16px', fontSize:13, lineHeight:1.8, color:'#ffffff'}}>
        <div style={{color:'#ffff00', fontWeight:700, fontSize:16, marginBottom:8, textTransform:'uppercase', letterSpacing:'0.1em'}}>📊 Why Tony Deserves Cooperstown:</div>
        <div>✅ Very fast. Like, VERY fast.</div>
        <div>✅ Stole 30 bases in 2012 (in limited at-bats)</div>
        <div>✅ Batted .261 one time</div>
        <div>✅ Great hair</div>
        <div>✅ His name sounds cool</div>
        <div>✅ Would definitely say hi to you at a Jewel-Osco</div>
        <div>✅ Once made eye contact with Ryne Sandberg</div>
      </div>

      {/* Guestbook */}
      <div style={{background:'#003300', border:'2px solid #00ff00', margin:'10px 12px', padding:'12px', borderRadius:4}}>
        <div style={{color:'#00ff00', fontWeight:700, fontSize:15, marginBottom:8}}>📝 GUESTBOOK (Read Only — We Lost the Password)</div>
        {[
          {user:'BaseballFan1998', msg:'Tony should 100% be in the HOF, my cousin saw him once'},
          {user:'CubsGirl_Tina', msg:'I have this card!! it is in great condition'},
          {user:'Tony_Campana_Fan_Account', msg:'First!!!'},
          {user:'StatNerd42', msg:'His WAR of 0.4 is... a number that exists'},
          {user:'WrigleyRegular', msg:'GOAT. No debate. Hall of Fame now.'},
        ].map((e,i) => (
          <div key={i} style={{borderBottom:'1px solid #005500', paddingBottom:6, marginBottom:6}}>
            <span style={{color:'#ffff00', fontWeight:700}}>{e.user}</span>
            <span style={{color:'#aaffaa', marginLeft:6}}>says: {e.msg}</span>
          </div>
        ))}
      </div>

      {/* Footer */}
      <div style={{textAlign:'center', padding:'16px 12px 30px', fontSize:11, color:'#888888'}}>
        <div style={{marginBottom:4}}>🌐 Best viewed in Internet Explorer 6.0 at 800×600 resolution 🌐</div>
        <div style={{marginBottom:4}}>⚠️ This site uses cookies. And also frames. And also JavaScript. ⚠️</div>
        <div>© 2011–Forever · Tony Campana HOF Fan Club · All Rights Reserved · Probably</div>
        <div style={{marginTop:10}}>
          <img src="https://web.archive.org/web/20091027051243/http://geocities.com/images/main/buttons/netscape.gif"
            style={{height:20, marginRight:4}} onError={e => e.target.style.display='none'}/>
        </div>
      </div>
    </div>
  );
}


function App() {
  const [state, setState]            = useState(loadState);
  const [liveScores, setLiveScores]  = useState({});
  const [fetchingIds, setFetchingIds]= useState(new Set());
  const [lastUpdated, setLastUpdated]= useState(null);
  const [year, setYear]              = useState(2026);
  const [tab, setTab]                = useState('schedule');
  const [campana, setCampana]        = useState(false);
  const [selectedGame, setSelectedGame] = useState(null);
  const [wrigleyB64, setWrigleyB64]  = useState('');
  const [logoB64, setLogoB64]        = useState('');
  const [darkMode, setDarkMode]      = useState(() => {
    try { return localStorage.getItem('cubs-dark') === 'true'; } catch { return false; }
  });
  const [fbReady, setFbReady]        = useState(false);
  const skipRead  = useRef(false); // skip our own write echoing back from Firebase
  const skipWrite = useRef(false); // skip write when Firebase pushes an update to us

  // Derive active theme — shadows module-level C inside App
  const C = darkMode ? C_DARK : C_LIGHT;

  // Scroll-driven header collapse — listen on window, not a div
  const [scrolled, setScrolled]     = useState(false);
  const [scrolledFar, setScrolledFar] = useState(false);
  const COLLAPSE_AT = 40;
  const FAR_AT      = 110;

  useEffect(() => {
    const onScroll = () => {
      const y = window.scrollY;
      setScrolled(y > COLLAPSE_AT);
      setScrolledFar(y > FAR_AT);
    };
    window.addEventListener('scroll', onScroll, {passive:true});
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  const scrollToTop = () => window.scrollTo({top:0, behavior:'smooth'});

  // When tab changes, snap back to top
  useEffect(() => { window.scrollTo({top:0}); setScrolled(false); setScrolledFar(false); }, [tab]);

  useEffect(() => {
    if (window.__WRIGLEY_B64__) setWrigleyB64(window.__WRIGLEY_B64__);
    if (window.__LOGO_B64__)    setLogoB64(window.__LOGO_B64__);
  }, []);

  // ── Firebase real-time sync ─────────────────────────────────────────────────
  useEffect(() => {
    if (!DB) return; // Firebase not configured — local-only mode
    const handler = DB.on('value', snap => {
      if (skipRead.current) { skipRead.current = false; return; }
      const data = snap.val();
      if (data) {
        // Merge CLAIMS_2026 as defaults so new seasons always appear
        skipWrite.current = true;
        setState(prev => ({ ...data, claims: { ...CLAIMS_2026, ...data.claims } }));
      } else {
        // First ever use — seed the database with defaults
        const init = buildInitialState();
        skipRead.current = true;
        DB.set(init);
        setState(init);
      }
      setFbReady(true);
    });
    return () => DB.off('value', handler);
  }, []);

  // Write state to Firebase + cache locally
  useEffect(() => {
    // Always keep a local cache for offline use
    try { localStorage.setItem(STORAGE_KEY, JSON.stringify(state)); } catch{}
    // Skip writing back to Firebase if this update came FROM Firebase
    if (skipWrite.current) { skipWrite.current = false; return; }
    if (!DB || !fbReady) return;
    skipRead.current = true; // our write will echo back — ignore it
    DB.set(state).catch(() => { skipRead.current = false; });
  }, [state, fbReady]);

  useEffect(() => {
    try { localStorage.setItem('cubs-dark', darkMode); } catch {}
  }, [darkMode]);

  const allScores = { ...state.cachedScores, ...liveScores };

  const fetchAllScores = useCallback(async () => {
    // Gather all past games across all seasons that need score fetching
    const toFetch = [];
    Object.entries(SEASONS).forEach(([yr, games]) => {
      games.forEach(g => {
        const key = `${yr}-${g.id}`;
        // 2025 games already have hardcoded scores in state; only fetch if missing
        // 2024 has no scores at all; 2026 needs live/recent scores
        if (isInPast(g.mlbDate) && !state.cachedScores[key]) {
          toFetch.push({key, mlbDate: g.mlbDate});
        }
      });
    });
    if (!toFetch.length) { setLastUpdated(new Date().toLocaleTimeString()); return; }
    setFetchingIds(new Set(toFetch.map(x=>x.key)));
    const results = await Promise.allSettled(toFetch.map(async({key,mlbDate}) => ({key, score:await fetchGameDetails(mlbDate)})));
    const newScores = {};
    results.forEach(r => { if(r.status==='fulfilled'&&r.value.score) newScores[r.value.key]=r.value.score; });
    setLiveScores(newScores);
    setFetchingIds(new Set());
    setLastUpdated(new Date().toLocaleTimeString());
  }, [state.cachedScores]);

  useEffect(() => { fetchAllScores(); }, [fetchAllScores]);

  const saveClaim = (gameId, yr, member) => {
    const key = `${yr}-${gameId}`;
    setState(prev => {
      const claims = {...prev.claims};
      if (member === '') delete claims[key]; else claims[key] = member;
      return {...prev, claims};
    });
  };
  const setMembers = ms => setState(prev => ({...prev, members:ms}));
  const renameMember = (oldName, newName) => setState(prev => {
    // Update the members list
    const members = prev.members.map(m => m === oldName ? newName : m);
    // Re-key every claim that was assigned to oldName
    const claims = Object.fromEntries(
      Object.entries(prev.claims).map(([k, v]) => [k, v === oldName ? newName : v])
    );
    return {...prev, members, claims};
  });

  const games = SEASONS[year];
  const winsThisYear   = Object.entries(allScores).filter(([k,s])=>k.startsWith(`${year}-`)&&s?.result==='W').length;
  const playedThisYear = Object.entries(allScores).filter(([k,s])=>k.startsWith(`${year}-`)&&s?.status==='Final').length;

  // Header height math
  // Photo: expanded = 210px (160 content + ~50px status bar clearance)
  // Collapsed = 100px (compact bar that still clears the status bar)
  const photoH        = scrolled ? 100 : 210;
  const yearBarVisible = !scrolledFar && tab === 'schedule';

  // The fixed header total height is used to push content down so it doesn't hide behind header
  // Approximate: photo + 3px stripe + (yearBar ? ~88px : 0)
  // We set this as a CSS var so content padding-top stays in sync
  const headerH = photoH + 3 + (yearBarVisible ? 88 : 0);

  const NAV_TABS = [
    ['schedule','Schedule',Icons.Schedule],
    ['stats','Stats',Icons.Stats],
    ['board','Leaderboard',Icons.Trophy],
    ['standings','Standings',Icons.Standings],
    ['roster','Settings',Icons.Settings],
  ];

  // Fixed nav height for bottom content padding
  const NAV_H = 56; // button content height; safe-area padding added on top

  return (
    <ThemeContext.Provider value={C}>
    <>
    {campana && <CampanaPage onBack={() => setCampana(false)} logoB64={logoB64}/>}
    {!campana && <div style={{background:C.cream, color:C.ink, minHeight:'100vh', maxWidth:480, margin:'0 auto', position:'relative', transition:'background-color 0.3s, color 0.3s'}}>

      {/* ── FIXED HEADER — sits at top:0, bleeds behind status bar ── */}
      <div style={{
        position:'fixed', top:0, left:'50%', transform:'translateX(-50%)',
        width:'100%', maxWidth:480,
        zIndex:100,
      }}>
        {/* Photo — pulls up by safe-area-inset-top so image fills behind dynamic island/status bar */}
        <div style={{
          height: `calc(${photoH}px + env(safe-area-inset-top))`,
          marginTop: 'calc(-1 * env(safe-area-inset-top))',
          overflow:'hidden', position:'relative', background:C.blue,
          transition:'height 0.35s cubic-bezier(0.4,0,0.2,1)',
        }}>
          {wrigleyB64 && (
            <img src={`data:image/jpeg;base64,${wrigleyB64}`} alt="Wrigley Field" style={{
              width:'100%', height:'100%',
              objectFit:'cover', objectPosition:'center 20%',
              filter:'brightness(0.55) saturate(0.75)',
            }}/>
          )}
          <div style={{position:'absolute',inset:0,background:'linear-gradient(to bottom, rgba(0,0,0,0.05) 0%, rgba(14,51,134,0.25) 55%, rgba(14,51,134,0.80) 100%)'}}/>
          <div className="pinstripe" style={{position:'absolute',inset:0,opacity:0.3}}/>

          {/* Text pinned to bottom; paddingTop pushes content below status bar when expanded */}
          <div style={{
            position:'absolute', bottom:0, left:0, right:0,
            padding: scrolled ? '0 14px 8px' : '0 16px 12px',
            transition:'padding 0.3s',
          }}>
            <div style={{display:'flex',alignItems:'center',gap:10}}>
              {logoB64 && (
                <img src={`data:image/png;base64,${logoB64}`} alt="Cubs" onClick={() => setCampana(c => !c)} style={{
                  width: scrolled ? 26 : 36, height: scrolled ? 26 : 36,
                  borderRadius:'50%', flexShrink:0,
                  boxShadow:'0 2px 8px rgba(0,0,0,0.6)',
                  transition:'width 0.35s,height 0.35s',
                  cursor:'pointer',
                }}/>
              )}
              <div>
                {!scrolled && <div style={{fontSize:10,color:'rgba(255,255,255,0.5)',fontFamily:"'Bebas Neue',sans-serif",letterSpacing:'0.25em',marginBottom:3}}>CHICAGO CUBS · EST. 1876</div>}
                <div style={{fontSize:scrolled?15:22, fontWeight:900, color:'#fff', fontFamily:"'Bebas Neue',sans-serif", fontStyle:'italic', lineHeight:1, transition:'font-size 0.35s'}}>Cubs Season Ticket Share</div>
                {!scrolled && <div style={{fontSize:12,color:'rgba(255,255,255,0.65)',fontFamily:"'Montserrat',sans-serif",letterSpacing:'0.06em',marginTop:4}}>Sec 213 · Row 2 · Seats 3 &amp; 4</div>}
              </div>
            </div>
          </div>
        </div>

        {/* Pinstripe divider */}
        {/* Pinstripe divider removed */}

        {/* Year + stats bar — schedule tab only */}
        <div style={{
          background:C.cream,
          borderBottom:`1px solid ${C.border}`,
          overflow:'hidden',
          maxHeight: yearBarVisible ? 120 : 0,
          opacity: yearBarVisible ? 1 : 0,
          transition:'max-height 0.35s cubic-bezier(0.4,0,0.2,1), opacity 0.25s',
        }}>
          <div style={{display:'flex',padding:'8px 12px 6px',gap:6}}>
            {SEASON_YEARS.map(yr => (
              <button key={yr} onClick={()=>setYear(yr)} style={yearBtnStyle(year===yr, C)}>
                {yr}
              </button>
            ))}
          </div>
          <div style={{display:'flex',borderTop:`1px solid ${C.border}`}}>
            {[[playedThisYear,'Played'],[`${winsThisYear}–${playedThisYear-winsThisYear}`,'W–L']].map(([v,l],i)=>(
              <div key={l} style={{flex:1,display:'flex',flexDirection:'column',alignItems:'center',padding:'7px 0',borderRight:i<1?`1px solid ${C.border}`:'none'}}>
                <div style={{fontSize:21,fontWeight:900,color:C.blue,fontFamily:"'Bebas Neue',sans-serif",lineHeight:1}}>{v}</div>
                <div style={{fontSize:10,color:C.muted,fontFamily:"'Bebas Neue',sans-serif",letterSpacing:'0.12em',marginTop:2}}>{l}</div>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* ── PAGE CONTENT — pushed down by fixed header height ── */}
      <div style={{
        paddingTop: `calc(${photoH}px + 3px + ${yearBarVisible ? 88 : 0}px + env(safe-area-inset-top))`,
        paddingBottom: `calc(${NAV_H}px + env(safe-area-inset-bottom) + 8px)`,
        transition: 'padding-top 0.35s cubic-bezier(0.4,0,0.2,1)',
      }}>
        {tab==='schedule' && <ScheduleTab     year={year} games={games} claims={state.claims} scores={allScores} fetchingIds={fetchingIds} members={state.members} onGameClick={setSelectedGame}/>}
        {tab==='stats'    && <StatsTab        claims={state.claims} scores={allScores} members={state.members}/>}
        {tab==='board'    && <LeaderboardTab  claims={state.claims} scores={allScores} members={state.members}/>}
        {tab==='standings' && <StandingsTab/>}
        {tab==='roster'   && <RosterTab       members={state.members} setMembers={setMembers} renameMember={renameMember} onRefresh={fetchAllScores} lastUpdated={lastUpdated} onToggleDark={() => setDarkMode(d => !d)} fbReady={fbReady}/>}
      </div>

      {/* ── SCROLL TO TOP FAB ── */}
      {scrolledFar && (
        <button onClick={scrollToTop} style={{
          position:'fixed',
          right:16,
          bottom:`calc(${NAV_H}px + env(safe-area-inset-bottom) + 16px)`,
          width:42, height:42, borderRadius:'50%',
          background:C.red, border:'2px solid rgba(255,255,255,0.2)',
          color:C.cream, fontSize:20,
          display:'flex', alignItems:'center', justifyContent:'center',
          cursor:'pointer', boxShadow:'0 4px 16px rgba(0,0,0,0.5)',
          zIndex:90,
        }}>↑</button>
      )}

      {/* ── FIXED BOTTOM NAV ── */}
      <div style={{
        position:'fixed', bottom:0, left:'50%', transform:'translateX(-50%)',
        width:'100%', maxWidth:480,
        background:C.cream,
        borderTop:`2px solid ${C.green}`,
        display:'flex', zIndex:100,
        paddingBottom:'env(safe-area-inset-bottom)',
        boxShadow:'0 -1px 0 rgba(0,0,0,0.06)',
      }}>
        {NAV_TABS.map(([key,lbl,Icon])=>(
          <button key={key} onClick={()=>setTab(key)} style={{flex:1,display:'flex',flexDirection:'column',alignItems:'center',gap:3,background:'none',border:'none',color:tab===key?C.blue:C.muted,cursor:'pointer',padding:'10px 0 8px',transition:'color 0.15s',position:'relative'}}>
            <Icon/>
            <span style={{fontSize:10,fontFamily:"'Bebas Neue',sans-serif",letterSpacing:'0.08em',fontWeight:tab===key?700:400}}>{lbl.toUpperCase()}</span>
            {tab===key && <div style={{width:'100%',height:3,background:C.green,borderRadius:0,position:'absolute',top:0,left:0}}/>}
          </button>
        ))}
      </div>

      {/* ── MODAL ── */}
      {selectedGame && (
        <GameModal
          game={selectedGame}
          year={year}
          score={allScores[`${year}-${selectedGame.id}`]}
          claimed={state.claims[`${year}-${selectedGame.id}`]}
          members={state.members}
          wrigleyB64={wrigleyB64}
          onClose={()=>setSelectedGame(null)}
          onSave={saveClaim}
        />
      )}
    </div>}
    </>
    </ThemeContext.Provider>
  );
}

ReactDOM.createRoot(document.getElementById('root')).render(<App/>);
